        int count = 0;
        int abit,bbit,cbit;
        int num = floor(max(log2(a), max(log2(b), log2(c)))) +1;
        for (int i = 0; i < num; i++){
            abit = (a >> i) & 1;
            bbit = (b >> i) & 1;
            cbit = (c >> i) & 1;

            if((abit | bbit) != cbit)
            count += (abit && bbit)? 2:1;
        }
        return count;
    }
};
